+
+      adapter.setHttpPostFn(async () => 503);
+
+      const payload: NotificationPayload = {
+        type: 'order:confirmation',
+        recipient: 'user-123',
+        subject: 'Test',
+        body: 'Test',
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result).toBe(false);
+      expect(adapter.getDeliveries()).toHaveLength(0);
+    });
