+      const custom = new WebhookNotificationAdapter({
+        url: 'https://api.example.com/hooks',
+        maxRetries: 5,
+        timeoutMs: 10000,
+      });
+      const config = custom.getConfig();
+      expect(config.url).toBe('https://api.example.com/hooks');
+      expect(config.maxRetries).toBe(5);
+      expect(config.timeoutMs).toBe(10000);
+      expect(config.retryDelayMs).toBe(200); // still default
+    });
+  });
+
+  describe('clearDeliveries', () => {
+    it('should clear delivery history', async () => {
+      await adapter.send({
+        type: 'order:confirmation',
+        recipient: 'user-123',
+        subject: 'Test',
+        body: 'Test',
+      });
+
+      expect(adapter.getDeliveries()).toHaveLength(1);
+      adapter.clearDeliveries();
+      expect(adapter.getDeliveries()).toHaveLength(0);
+    });
+  });
+
+  describe('channel', () => {
+    it('should report webhook as its channel', () => {
+      expect(adapter.channel).toBe('webhook');
+    });
+  });
+});
+
+describe('isValidWebhookUrl', () => {
+  it('should accept valid HTTP URLs', () => {
+    expect(isValidWebhookUrl('http://localhost:8080/webhooks')).toBe(true);
+    expect(isValidWebhookUrl('http://example.com/hook')).toBe(true);
+  });
+
+  it('should accept valid HTTPS URLs', () => {
+    expect(isValidWebhookUrl('https://api.example.com/webhooks')).toBe(true);
+    expect(isValidWebhookUrl('https://hooks.slack.com/services/T00/B00/xxx')).toBe(true);
+  });
+
+  it('should reject invalid URLs', () => {
+    expect(isValidWebhookUrl('not-a-url')).toBe(false);
+    expect(isValidWebhookUrl('')).toBe(false);
+    expect(isValidWebhookUrl('ftp://example.com/hook')).toBe(false);
+    expect(isValidWebhookUrl('ws://example.com/hook')).toBe(false);
+  });
+});
+
+describe('formatWebhookPayload', () => {
+  it('should format notification payload as webhook body', () => {
+    const payload: NotificationPayload = {
+      type: 'order:confirmation',
+      recipient: 'user-123',
+      subject: 'Order Confirmation: order-1',
+      body: 'Items: Widget x2',
+      metadata: { orderId: 'order-1' },
+    };
+
+    const result = formatWebhookPayload(payload);
+
+    expect(result.type).toBe('order:confirmation');
+    expect(result.recipient).toBe('user-123');
+    expect(result.subject).toBe('Order Confirmation: order-1');
+    expect(result.body).toBe('Items: Widget x2');
+    expect(result.metadata).toEqual({ orderId: 'order-1' });
+    expect(result.timestamp).toBeDefined();
+  });
+
+  it('should handle payload without metadata', () => {
+    const payload: NotificationPayload = {
+      type: 'user:welcome',
+      recipient: 'user-456',
+      subject: 'Welcome!',
+      body: 'Hello!',
+    };
+
+    const result = formatWebhookPayload(payload);
+
+    expect(result.metadata).toBeUndefined();
+    expect(result.type).toBe('user:welcome');
+  });
+});

