  describe('retry behavior', () => {
    it('should retry on transient HTTP failure and succeed', async () => {
      adapter = new WebhookNotificationAdapter({ maxRetries: 2, retryDelayMs: 1 });

      let attempts = 0;
      adapter.setHttpPostFn(async () => {
        attempts++;
        if (attempts < 2) {
          throw new Error('Connection refused');
        }
        return 200;
      });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'user-123',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      expect(attempts).toBe(2);
      expect(adapter.getDeliveries()).toHaveLength(1);
    });

    it('should fail after exhausting all retries', async () => {
      adapter = new WebhookNotificationAdapter({ maxRetries: 1, retryDelayMs: 1 });

      adapter.setHttpPostFn(async () => {
        throw new Error('Server unreachable');
      });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'user-123',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(false);
      expect(adapter.getDeliveries()).toHaveLength(0);
    });

    it('should retry when server returns non-2xx status', async () => {
      adapter = new WebhookNotificationAdapter({ maxRetries: 2, retryDelayMs: 1 });

      let attempts = 0;
      adapter.setHttpPostFn(async () => {
        attempts++;
        return attempts >= 3 ? 200 : 500;
      });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'user-123',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      expect(attempts).toBe(3);
    });

    it('should fail when server consistently returns non-2xx', async () => {
      adapter = new WebhookNotificationAdapter({ maxRetries: 1, retryDelayMs: 1 });

      adapter.setHttpPostFn(async () => 503);

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'user-123',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(false);
      expect(adapter.getDeliveries()).toHaveLength(0);
    });
  });

  describe('configuration', () => {
    it('should use default config', () => {
      const config = adapter.getConfig();
      expect(config.url).toBe('http://localhost:8080/webhooks');
      expect(config.maxRetries).toBe(3);
      expect(config.retryDelayMs).toBe(200);
      expect(config.timeoutMs).toBe(5000);
    });

    it('should accept custom config', () => {
      const custom = new WebhookNotificationAdapter({
        url: 'https://api.example.com/hooks',
        maxRetries: 5,
        timeoutMs: 10000,
      });
      const config = custom.getConfig();
      expect(config.url).toBe('https://api.example.com/hooks');
      expect(config.maxRetries).toBe(5);
      expect(config.timeoutMs).toBe(10000);
      expect(config.retryDelayMs).toBe(200); // still default
    });
  });

  describe('clearDeliveries', () => {
    it('should clear delivery history', async () => {
      await adapter.send({
        type: 'order:confirmation',
        recipient: 'user-123',
        subject: 'Test',
        body: 'Test',
      });

      expect(adapter.getDeliveries()).toHaveLength(1);
      adapter.clearDeliveries();
      expect(adapter.getDeliveries()).toHaveLength(0);
    });
  });

  describe('channel', () => {
    it('should report webhook as its channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });
});

